import{_ as i,o as t,c as s,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"Suivi & Reporting","description":"","frontmatter":{"title":"Suivi & Reporting"},"headers":[],"relativePath":"docs/fr/publishers/sponsored-mail/reporting.md","filePath":"docs/fr/publishers/sponsored-mail/reporting.md"}'),a={name:"docs/fr/publishers/sponsored-mail/reporting.md"};function d(o,e,n,l,p,u){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="suivi-des-volumes-reporting" tabindex="-1">Suivi des Volumes (Reporting) <a class="header-anchor" href="#suivi-des-volumes-reporting" aria-label="Permalink to &quot;Suivi des Volumes (Reporting)&quot;">​</a></h1><p>Le reporting régulier est indispensable pour assurer le suivi de la consommation des stocks et la facturation.</p><hr class="my-6"><h2 class="text-purple-200 mb-4">📅 L&#39;obligation hebdomadaire</h2><div style="border:2px solid var(--gi-accent);background:var(--gi-tint-blue-bg);padding:24px;border-radius:8px;margin-bottom:40px;"><div style="display:flex;align-items:center;gap:20px;"><div style="font-size:40px;">🗓️</div><div><h3 class="mt-0 text-purple-200">Chaque début de semaine</h3><p class="fs-4 mb-0">Vous devez déclarer le volume exact d&#39;asiles distribués au cours de la semaine précédente (Lundi ou Mardi).</p></div></div></div><h2 class="text-grey-dk-000 mb-4">Comment déclarer les volumes ?</h2><div style="display:flex;gap:20px;margin-bottom:20px;"><div style="flex-shrink:0;width:30px;height:30px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;">1</div><div>Connectez-vous à <a href="https://app.getinside.media/">app.getinside.media</a>.</div></div><div style="display:flex;gap:20px;margin-bottom:20px;"><div style="flex-shrink:0;width:30px;height:30px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;">2</div><div>Allez dans <strong>&quot;Mes Campagnes&quot;</strong> et sélectionnez la campagne active.</div></div><div style="display:flex;gap:20px;margin-bottom:20px;"><div style="flex-shrink:0;width:30px;height:30px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;">3</div><div>Ouvrez l&#39;onglet <strong>&quot;Configuration et suivi&quot;</strong>.</div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:30px;height:30px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;">4</div><div> Dans le tableau de suivi, saisissez : <ul><li>La période (ex: Semaine 42).</li><li>La quantité insérée.</li></ul></div></div><h2 class="text-grey-dk-000 mb-4">Fin de campagne</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(300px, 1fr));gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;"><h3 class="mt-0 fs-4">Cas A : Stock Épuisé</h3><p class="fs-2 text-grey-dk-000 mb-0">Vous avez distribué tous les supports reçus. La campagne s&#39;arrête naturellement.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:8px;padding:20px;"><h3 class="mt-0 fs-4">Cas B : Objectif Atteint</h3><p class="fs-2 text-grey-dk-000 mb-0">Le volume commandé (Capped) est atteint, même s&#39;il reste du stock (sauf instruction contraire pour écouler le reliquat).</p></div></div><div style="margin-top:20px;text-align:center;"><p>Une fois terminée, cliquez sur le bouton <strong>&quot;Clôturer la campagne&quot;</strong> pour valider la prestation.</p></div>',13)])])}const v=i(a,[["render",d]]);export{g as __pageData,v as default};
